"""
This module represents the Checkers (Draughts) game board.
"""

class GameBoard:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('B')
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('W')

    def print_board(self):
        for row in self.board:
            print(" ".join([str(piece) if piece else '.' for piece in row]))

    def update_piece_position(self, old_pos, new_pos):
        piece = self.board[old_pos[0]][old_pos[1]]
        self.board[old_pos[0]][old_pos[1]] = None
        self.board[new_pos[0]][new_pos[1]] = piece

    def get_piece(self, position):
        return self.board[position[0]][position[1]]

class Piece:
    def __init__(self, color, is_king=False):
        self.color = color
        self.is_king = is_king

    def __str__(self):
        if self.is_king:
            return 'K' if self.color == 'B' else 'k'
        return 'P' if self.color == 'B' else 'p'

