"""
This module represents a player in the Checkers (Draughts) game.
"""

class Player:
    def __init__(self, color):
        self.color = color

    def make_move(self, board, old_pos, new_pos):
        piece = board.get_piece(old_pos)
        if piece and piece.color == self.color:
            board.update_piece_position(old_pos, new_pos)

