"""
This module manages the Checkers (Draughts) game state.
"""

from player import Player
from game_board import GameBoard

class GameController:
    def __init__(self):
        self.board = GameBoard()
        self.players = [Player('B'), Player('W')]
        self.current_player_index = 0

    def switch_player(self):
        self.current_player_index = 1 - self.current_player_index

    def play_game(self):
        while True:
            self.board.print_board()
            current_player = self.players[self.current_player_index]
            move = input(f"Player {current_player.color}, enter your move (e.g., 2,4 -> 3,5): ")
            old_pos = tuple(map(int, move.split('->')[0].split(',')))
            new_pos = tuple(map(int, move.split('->')[1].split(',')))
            current_player.make_move(self.board, old_pos, new_pos)
            self.switch_player()

if __name__ == "__main__":
    game_controller = GameController()
    game_controller.play_game()

